mapper.insert:
insert into biz_finance_budget(
  budget_no, budget_year, department_id, instrument_id, budget_amount,
  warning_ratio, status, remark, operator_user_id, create_time, update_time
) values (
  #{budgetNo}, #{budgetYear}, #{departmentId}, #{instrumentId}, #{budgetAmount},
  #{warningRatio}, #{status}, #{remark}, #{operatorUserId}, #{createTime}, #{updateTime}
)

mapper.select:
select b.*, d.dept_name as department_name, i.instrument_name, u.real_name as operator_user_name
from biz_finance_budget b
left join sys_department d on d.id = b.department_id
left join biz_instrument i on i.id = b.instrument_id
left join sys_user u on u.id = b.operator_user_id
where 1 = 1

  and b.budget_year = #{budgetYear}


  and b.department_id = #{departmentId}


  and b.instrument_id = #{instrumentId}


  and b.status = #{status}


  and b.department_id = #{scopeDepartmentId}

order by b.budget_year desc, b.create_time desc
limit #{offset}, #{pageSize}

select count(1)
from biz_finance_budget b
where 1 = 1

  and b.budget_year = #{budgetYear}


  and b.department_id = #{departmentId}


  and b.instrument_id = #{instrumentId}


  and b.status = #{status}


  and b.department_id = #{scopeDepartmentId}

select b.*, d.dept_name as department_name, i.instrument_name, u.real_name as operator_user_name from biz_finance_budget b left join sys_department d on d.id = b.department_id left join biz_instrument i on i.id = b.instrument_id left join sys_user u on u.id = b.operator_user_id where b.status = 'ENABLED'
and b.budget_year = #{budgetYear}
and b.department_id = #{scopeDepartmentId}
order by b.budget_year desc, b.create_time desc
